# DFA nhan dang chuoi ket thuc bang 'ab' tren {a,b}
dfa = {
    'q0': {'a': 'q1', 'b': 'q0'},
    'q1': {'a': 'q1', 'b': 'q2'},
    'q2': {'a': 'q1', 'b': 'q0'},
}
start, accept = 'q0', {'q2'}

def run_dfa(s):
    state = start
    trace = [state]
    for ch in s:
        state = dfa[state][ch]
        trace.append(state)
    return state in accept, trace

for w in ['ab', 'aab', 'bab', 'ba', 'abab']:
    ok, trace = run_dfa(w)
    print('"' + w + '" => ' + ' -> '.join(trace) + ' : ' + ('ACCEPT' if ok else 'REJECT'))

import re

def in_anbn(s):
    m = re.fullmatch(r'(a+)(b+)', s)
    if not m: return False
    return m.group(1).count('a') == m.group(2).count('b')

tests = ['ab', 'aabb', 'aaabbb', 'aab', 'abb', 'aaabb']
print('L = a^n b^n (CFG, not Regular):')
for w in tests:
    print(f'  "{w}" => {in_anbn(w)}')

